INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-5', 'task', NULL, 'harden plan export hook: --stage flag + absolute pql path', 'Two related issues with the pre-commit hook installed by pql init:

1. Staging logic lives in shell, not pql. Move it into ''pql plan export --stage'' so pql owns the git-add edge cases (untracked / gitignored / dirty). Bare ''pql plan export'' stays side-effect-free; --stage opts in. Update internal/cli/init.go''s pqlPreCommitHook to call ''pql plan export --stage'' (one line, no [ -f ] test).

2. Hook silently no-ops when pql isn''t on PATH for git''s hook shell (witnessed locally — git commit -m ''...'' didn''t fire the hook even though pql was on the user''s interactive PATH). Fix: at pql init time, resolve os.Executable() and bake the absolute path into the generated hook script instead of ''pql''. Drop the ''command -v pql'' guard since the absolute path either exists or it doesn''t.

Touches: internal/cli/init.go (hook content), internal/cli/plan.go (export verb adds --stage flag and stage helper). Requires a new repo-level helper or direct git shell-out for the staging step. Add tests: hook-content assertion that the resolved path is baked in; cli test for ''plan export --stage'' both when file is untracked and when it''s already tracked.', 'done', 'high', 'claude', NULL, NULL, '2026-05-06 10:14:20', '2026-05-06 12:21:04', NULL, '62bff0c044f3aee8f6234f18e7adfe96', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-4', 'bug', NULL, 'pre-commit hook misses bootstrap snapshot when pql-plan.json is untracked', 'internal/cli/init.go:374 pqlPreCommitHook gates ''git add'' on ''git diff --quiet -- .pql/pql-plan.json''. For an untracked file, git diff returns 0 (no diff) so the negation is false and the file is never staged. Result: the first commit after ''pql init'' silently fails to commit the planning snapshot. Reproducer: fresh repo, pql init, pql ticket new ..., git commit -m ''...'' — pql-plan.json stays untracked. Fix: also stage when the file exists but is untracked, e.g. test ''git ls-files --error-unmatch ... 2>/dev/null'' or unconditionally ''git add -f .pql/pql-plan.json'' if the file exists. Update both the embedded hook script and any tests asserting hook behaviour.', 'done', 'high', 'claude', NULL, NULL, '2026-05-06 10:11:03', '2026-05-06 12:21:04', NULL, '724f369288d76a67ea8fa69ec3926807', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-2', 'task', 'T-1', 'route plan whatsnext and plan review through buildShowTree', 'Replace whatNextResult in internal/cli/plan.go with the ticketShowTree shape (or refactor whatNextResult to embed it). enrichTicket already returns the same ancestors/children/decisions data — collapse the two so plan whatsnext, plan review, ticket show, and ticket refine emit identical join-tree JSON for the same ticket. Keep the Message field for the no-actionable-tickets case.', 'done', 'medium', 'claude', NULL, NULL, '2026-05-06 10:07:05', '2026-05-06 12:21:04', NULL, 'b6262250e7d541da3efb035a2951493d', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-6', 'bug', NULL, 'pql init writes hooks to .git/hooks/ even when core.hooksPath is redirected', 'When git''s core.hooksPath config points at a custom directory (this repo uses ''.githooks/'' for its pre-push gate), git ignores .git/hooks/ entirely — so the pql shim ensureGitHookShim writes there is never invoked, and the .pql/hooks/{pre-commit,post-merge} scripts never fire from git commit / git pull. Witnessed locally: the show-tree unification commit (T-2) didn''t auto-stage .pql/pql-plan.json even though pql plan export --stage works correctly when run by hand.

Reproducer: ''git config core.hooksPath .githooks'' in any pql-init''d repo. Commits stop carrying the snapshot.

Fix: ensureGitHookShim in internal/cli/init.go should resolve the effective hooks path. Two strategies:
  1. Read ''git config --get core.hooksPath'' (or the equivalent env var GIT_HOOKS_PATH) and write the shim there. If the directory doesn''t exist or isn''t writable, surface a clear note in the init JSON output rather than silently planting a dead shim.
  2. Append to an existing pre-commit/post-merge shim in that directory rather than overwriting (so the project''s own hook keeps working alongside pql''s).

Test: assert ensurePlanExportHook with a pre-set core.hooksPath writes into the redirected dir, not .git/hooks/.', 'done', 'high', 'claude', NULL, NULL, '2026-05-06 12:08:36', '2026-05-06 12:21:19', NULL, '4b19836893aef9f96e44b9255522f705', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-1', 'story', NULL, 'unify show-tree rendering across ticket and decision surfaces', 'Audit which surfaces build a ticket/decision join-tree (ancestors, decisions, blockers, children) and route them all through buildShowTree (introduced in v1.4.5 in internal/cli/ticket.go). Currently used by ticket show, ticket refine next, ticket refine write. Plan whatsnext / plan review use the older whatNextResult shape; decisions show may have a parallel pattern. Goal: one canonical helper, identical JSON output where the data overlaps, single place to tweak rendering.', 'done', 'medium', 'claude', NULL, NULL, '2026-05-06 10:07:05', '2026-05-06 12:26:16', NULL, '1986b8ec19dc3e65ff226c8ac08a35ad', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-3', 'task', 'T-1', 'align decisions show with the join-tree helper pattern', 'Audit internal/cli/decisions.go (decisions show with --with-refs / --with-tickets) for a parallel ad-hoc tree shape. If found, factor into a buildDecisionTree helper analogous to buildShowTree so decision rendering stays consistent across decisions show, decisions read, and any future surface (e.g. plan status drilldowns).', 'done', 'medium', 'claude', NULL, NULL, '2026-05-06 10:07:05', '2026-05-06 12:26:16', NULL, '6b2fee6083586befa31f6bdd7c63b507', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-8', 'task', 'T-7', 'draft clean-house SKILL.md + references/rules.md', 'Create internal/skill/clean-house/{SKILL.md,references/rules.md}. SKILL.md is the v1.0 integrated form (Claude as runtime; no Python stopgap framing). references/rules.md contains 6-8 starter rules with explicit Detection sections that name the pql query / file primitive each needs — that detection list reveals the pql gaps for follow-up tickets.', 'done', 'medium', 'claude', NULL, NULL, '2026-05-06 12:38:49', '2026-05-06 12:42:06', NULL, '2aaeba6b60f9bb7fc00261a0e4741e6e', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-9', 'task', 'T-7', 'expose decision body heading anchors on pql decisions read', 'Add a ''headings: [{level, text, slug}]'' array to the JSON returned by ''pql decisions read <id>''. The slug must follow the same convention used by markdown anchor links in the source (typically lowercase-hyphen — match the project''s existing slugger; check whether one already lives in internal/index/parser/markdown for headings used elsewhere). Required for clean-house RULE-ANCHOR-DRIFT detection — without it, the skill cannot resolve cross-reference link targets to existing headings without re-parsing the body.', 'done', 'high', 'claude', NULL, NULL, '2026-05-06 12:42:06', '2026-05-06 13:01:55', NULL, '5649947d206ecebc0a6a1de5d2a61ac4', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-10', 'task', 'T-7', 'extend skill installer to ship clean-house as sub-skill', 'Refactor internal/skill/ so the installer can ship multiple skills. Today it embeds one SKILL.md from internal/skill/SKILL.md and writes to .claude/skills/pql/SKILL.md. Need to also embed internal/skill/clean-house/{SKILL.md,references/rules.md} and write to .claude/skills/clean-house/. The install lockfile (.pql-install.json) extends to track both skills'' state. Updates: pql skill install, pql skill status, pql doctor, pql init''s --with-skill flag (if relevant). Tests: skill install creates both directories; --force refreshes both; status correctly reports each independently.', 'done', 'medium', 'claude', NULL, NULL, '2026-05-06 12:42:06', '2026-05-06 13:30:09', NULL, '043ef00d484928bd8bd8e79e49884fa1', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-7', 'story', NULL, 'ship clean-house skill v1.0 as pql sub-skill', 'Add a clean-house skill to the pql installer that runs documentation-discipline passes over a DQR (Decisions / Questions / Rejected) markdown system. Claude is the runtime (no external script); the skill walks decisions/, runs the rule catalog, batches findings via AskUserQuestion, and applies fixes via pql queries + Edit. Pql remains a dumb data layer — gets new queries only when the skill names one.', 'done', 'medium', 'claude', NULL, NULL, '2026-05-06 12:38:49', '2026-05-06 13:30:09', NULL, '31ee4d74277da505dfa28e03f2650d74', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-11', 'task', NULL, 'auto-resolve skill scope: user-scope wins when present', 'pql skill install (no --user flag) should auto-resolve which scope to operate on:

  - If ANY bundled skill is already installed at user-scope (~/.claude/skills/<name>/), treat user-scope as canonical for the whole suite. Install/update every bundled skill there. Do not touch project-scope.

  - If no user-scope install exists, install at project-scope (current behavior).

  - --user flag still forces user-scope unconditionally — only way to make the *initial* user-scope install.

When auto-resolving to user-scope, also tidy up any safely-removable project-scope install (state in {current, stale, missing}). Preserve project-scope if state is modified or unknown — the user has hand-edits, do not nuke them; surface a note instead.

This same resolution applies to:
  - pql skill status (no flag) — report effective scope
  - pql init skill step — install/update at the resolved scope
  - pql skill uninstall (no flag) — operate on project-scope only (do not surprise users by removing user-scope without --user). Note when user-scope exists.

pql doctor should report BOTH scopes so drift between them stays visible.

Add a Scope field on the per-skill JSON output (user | project) so callers can tell which install they are looking at.', 'done', 'high', 'claude', NULL, NULL, '2026-05-06 13:36:08', '2026-05-06 13:42:40', NULL, '02376677fea8c0ebc7796dae80c67c00', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-12', 'task', NULL, 'Track conditions for D-1 revisit', 'D-1 commits to no vector retrieval but documents two AND-conditions for revisiting: (a) a specific class of agent task is shown, with examples, to fail on structured retrieval and succeed on semantic; AND (b) a pure-Go embedded vector store reaches tier-one quality. Either alone is insufficient. This ticket exists to surface the revisit gate in plan whatsnext / plan board so the trigger doesn''t get forgotten if/when the conditions arrive. No work to do until both fire — the ticket stays in backlog as a sentinel.', 'backlog', 'low', NULL, NULL, 'D-1', '2026-05-06 14:00:50', '2026-05-06 14:00:50', NULL, 'd7eb0bdfc5de232c653e3018730a5cc5', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-13', 'task', NULL, 'tighten clean-house rules.md (catalog fixes)', 'Three changes to internal/skill/clean-house/references/rules.md, surfaced by the first end-to-end clean-house run:\n\n1. RULE-ANCHOR-DRIFT detection rewrite. Current logic checks anchor links against the referenced record''s body headings (from pql decisions read), but anchor-only links resolve against the file''s full heading set — including record-level ''### D-N: …'' headings stripped from the body. Replace detection with: read the source body''s *file* (decisions/<file>), extract every ATX heading, build a file-level slug index, check anchor-only links against that. Cross-file anchors (path.md#slug) check the path''s slug index.\n\n2. RULE-DEAD-FILE-REFERENCE filtering. Detection produced 6/6 false positives this run: placeholder tokens (tickets/T-NNN.md, sessions/.../brief.md), package-relative refs (repo/tickets.go for the real internal/planning/repo/tickets.go), sibling-relative refs (questions.md from a body in decisions/, resolved against repo root). Add to detection: skip tokens containing ''T-NNN'', ''...'', ''<'', ''>''; resolve relative paths against the source file''s directory before os.Stat; fallback to basename-match across the repo (find -name) before flagging.\n\n3. Per-rule Finding ID format. Each rule entry needs a ''Finding ID:'' field so the skip ledger can re-recognize the same finding across runs (precondition for the 3-strikes promote-prompt logic). Examples: RULE-ANCHOR-DRIFT → ''<source-record>:<target-slug>''; RULE-SUNSET-WITHOUT-TICKET → ''<record-id>:<phrase-hash-8>''; RULE-FILE-OVER-THRESHOLD → ''<file-path>''.', 'done', 'high', 'claude', NULL, NULL, '2026-05-06 14:35:25', '2026-05-06 14:36:54', NULL, 'ca990d590475e5a5b8ee6229aa394b25', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-14', 'task', NULL, 'tighten clean-house SKILL.md (procedure + state)', 'Five changes to internal/skill/clean-house/SKILL.md, surfaced by the first end-to-end clean-house run:\n\n1. Add step 1.5 ''Probe conventions''. Read decisions/.clean-house.yaml if present; otherwise infer from the project: heading depth (## vs ###), backlink phrasing (Resolves: vs other), staleness threshold (default 60). Rules.md entries should consume these probed values instead of hardcoding. Also documents the .clean-house.yaml shape so projects can pin conventions explicitly.\n\n2. In step 4 ''Walk decisions/'', filter records whose file_path begins with ''legacy/''. The ''What this skill does NOT do'' bullet promises this but the procedure doesn''t enforce it.\n\n3. In step 6, define ''stop asking'' globally: exits all remaining prompts in the run (mechanical batches and judgment findings alike); everything pending lands in the skip ledger as deferred; summary still emitted.\n\n4. In step 7, define the ''show diff first'' loop: print unified diff of the staged edits, then re-prompt with the same options minus ''show diff first'' so the user can''t loop forever.\n\n5. Define the promotion-candidate history file. Output template promises ''RULE-X (5/7 runs)'' but no storage is named. Either repurpose the skip ledger with per-run section headers (timestamped, plus ''fired'' / ''skipped'' counts per rule) or add a sibling .clean-house-history.md. Pick one; document the shape.', 'done', 'high', 'claude', NULL, NULL, '2026-05-06 14:35:25', '2026-05-06 14:39:25', NULL, '33504c89f9d979363237f6320296f4d5', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-15', 'task', NULL, 'exempt stance-shaped decisions from coverage report', 'pql decisions coverage flags every confirmed D without a linked T. For pql itself, ~13 of 14 confirmed decisions are founding/architectural stances (D-2 ''intent-level surface'', D-4 ''consumer-agnostic core'', D-5 ''CLI-first, not MCP'', etc.) — they document commitments, not roadmap items. A T per stance is ceremony.\n\nProposal: introduce a frontmatter field on D records, e.g. ''coverage: stance'' (free-form values to grow later — ''roadmap'', ''sentinel'', ''stance'', default ''roadmap''). ''pql decisions coverage'' filters out non-roadmap by default; --include-stance shows the full set.\n\nTouches: internal/planning/parser/decisions.go (parse new field), internal/planning/repo/decisions.go (Decision struct), internal/cli/decisions.go (filter + flag in coverage subcommand), the existing decisions/*.md (annotate D-2 through D-14 as ''coverage: stance'' once the parser supports it). D-1 stays default (''roadmap'') because it has T-12 tracking its revisit gate.', 'backlog', 'low', NULL, NULL, NULL, '2026-05-06 15:04:02', '2026-05-06 15:04:02', NULL, '0898d9dd9da1ac12bfe8dd06bac016a4', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-16', 'story', NULL, 'implement changelog-based replication for planning state', 'Umbrella story for the changelog-based replication design captured in D-15 (changelog layout), D-16 (inline LWW guards + hashing), D-17 (soft deletes), and D-18 (hook architecture). Replaces the single mutable pql-plan.json snapshot (D-13, superseded) with .pql/changelog/<table>/ directories of per-month SQL upsert files plus per-table schema files. Children cover the discrete implementation slices: schema/columns, soft deletes, export rewrite, import rewrite, rebuild, init updates, legacy migration, schema-migration generation, and the clide integration test scenario. The original design doc at pql-plan-replication.md is retired in favour of these records — delete or archive once children land.', 'backlog', 'high', NULL, NULL, 'D-15', '2026-05-08 07:46:15', '2026-05-08 07:46:15', NULL, 'd9a7978f54847507fd7448cc8877da80', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-20', 'task', 'T-16', 'rewrite pql plan import to replay changelog directories', 'Replace JSON import with changelog replay. Walk .pql/changelog/<table>/ directories in lexicographic file order so 0000-schema.sql and other zero-prefixed schema files run before year-prefixed data files. Replay every line that hasn''t been seen since last_import_marker (tracked per-file via mtime or per-line via offset).

Import pipeline (internal/cli/plan.go + internal/planning/changelog/importer.go):
1. Read last_import_marker from pql.db meta.
2. For each .pql/changelog/<table>/ directory:
   a. Run files in lexicographic order, tracking position.
   b. Schema files apply via CREATE TABLE IF NOT EXISTS (idempotent).
   c. Data files: each line is an inline-guarded upsert; replay is idempotent because the WHERE clause from T-19 prevents stale lines from overwriting newer state.
3. Advance last_import_marker on success.

Idempotency is load-bearing: the same line replayed N times converges to the same result, regardless of starting state. This is the property that lets the hooks (D-18) be cheap and the import to fire from multiple paths (post-merge, pql plan rebuild) without coordination.

Touches: internal/cli/plan.go (import verb body), new internal/planning/changelog/importer.go, internal/planning/repo/meta.go. Tests: replay-twice convergence, replay-out-of-order convergence, schema_version mismatch handling (refuse and surface diagnostic), partial-replay resumption after interrupted run.', 'backlog', 'high', NULL, NULL, 'D-15', '2026-05-08 07:47:06', '2026-05-08 07:47:06', NULL, 'bc30e8c023965ec54d9ca3920f0d6724', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-21', 'task', 'T-16', 'implement pql plan rebuild for branch-switch and rebase recovery', 'New subcommand pql plan rebuild — drops planning tables and replays the full changelog from scratch. Used by post-checkout (branch switch) and post-rewrite (rebase) hooks because LWW-guarded incremental replay can only INSERT/UPDATE — it can''t remove rows that exist on the previous branch but not the new one.

Rebuild pipeline (internal/cli/plan.go):
1. DELETE FROM each planning table (or DROP and rely on schema files to recreate — simpler).
2. Reset last_import_marker, last_export_marker.
3. Run the import flow from T-20 against the entire changelog.
4. Stdout: summary (tables rebuilt, rows replayed, time taken).
5. Stderr: progress diagnostics for hook visibility.

Surface as a first-class command, not just a hook callee — power users may invoke it for disaster recovery or after manual changelog edits. Document under ''Plan subcommands'' in the skill.

Touches: internal/cli/plan.go (new rebuild verb), reuses the importer from T-20. Tests: rebuild-from-empty, rebuild-after-branch-with-deleted-rows (must not leak previous branch state), idempotent re-rebuild.', 'backlog', 'high', NULL, NULL, 'D-18', '2026-05-08 07:47:16', '2026-05-08 07:47:16', NULL, 'eb0b05cf1b21a2f114f8fc6df9ce482f', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-22', 'task', 'T-16', 'update pql init to install hooks, schema files, and gitattributes for replication', 'Extend internal/cli/init.go to wire the full replication lifecycle on a fresh clone or an upgraded repo:

1. Create .pql/changelog/ and per-table subdirectories (.pql/changelog/tickets/, .pql/changelog/audit_log/, .pql/changelog/refs/, etc. — every planning table that participates in replication).
2. Write 0000-schema.sql into each <table>/ directory containing the CREATE TABLE IF NOT EXISTS statement for that table. The migration runner (D-6) generates these from its current schema knowledge — reuse rather than duplicate.
3. Install four hooks (resolved absolute pql path, per the T-5 fix):
   - pre-commit: pql plan export --stage (existing path; just confirm the verb still does the right thing under the new exporter).
   - post-merge: pql plan import (silent if quick; default behaviour).
   - post-checkout: if [ "" = "1" ]; then echo ''rebuilding pql database...''; pql plan rebuild; fi
   - post-rewrite: echo ''rebuilding pql database after rewrite...''; pql plan rebuild
4. Write or amend .gitattributes with the line: .pql/changelog/*.sql merge=union
5. Stage all the above so the user''s first commit lands the new layout.

Touches: internal/cli/init.go (most of the work), reuses migration runner for schema generation, depends on T-19/T-20/T-21 verb behaviour. Tests: fresh-init produces all expected files; re-init is idempotent; .gitattributes append doesn''t duplicate the line if it''s already present.', 'backlog', 'high', NULL, NULL, 'D-18', '2026-05-08 07:47:34', '2026-05-08 07:47:34', NULL, '872c3ffa870b7d03298f50ed6cb429b5', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-23', 'task', 'T-16', 'migrate legacy pql-plan.json into the changelog on first export', 'Existing repos have committed pql-plan.json artifacts (per D-13, now superseded). On first pql plan export against an upgraded repo, detect the legacy file and convert it transparently:

1. Detect: .pql/changelog/ does not exist OR is empty AND pql-plan.json exists at the vault root.
2. Run pql plan import --legacy <pql-plan.json> to populate pql.db from the JSON snapshot (the existing import path is the migration tool).
3. Run pql plan export under the new format — this writes 0000-schema.sql and the initial data files into .pql/changelog/<table>/.
4. git rm pql-plan.json so the legacy artifact doesn''t linger.
5. Stage the new changelog directory, the schema files, and the deletion of pql-plan.json — all part of the same pre-commit hook invocation.
6. Stdout: clear migration message so the user knows what happened in the next commit.

The legacy import path needs a flag (--legacy) so it doesn''t conflict with the new replay-from-changelog import. After this migration commit lands, all future operations use the new format.

Touches: internal/cli/plan.go (legacy detection in export, --legacy flag on import), internal/cli/init.go (probably also runs the migration when init is run on an existing legacy repo). Tests: clide vault as the target — clone, run upgraded pql, observe transparent migration commit; verify subsequent flows use the new format.', 'backlog', 'high', NULL, NULL, 'D-15', '2026-05-08 07:47:46', '2026-05-08 07:47:46', NULL, '2e2925bc7dd163387f6f544e8d15631f', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-24', 'task', 'T-16', 'integrate schema migrations with numbered changelog schema files', 'Adapt the in-house migration runner (D-6) so schema migrations land in the changelog directories as numbered files rather than (or in addition to) inline Go SQL.

Naming convention: <NNNN>-schema-<slug>.sql in each .pql/changelog/<table>/. Lexicographic sort puts these before <YYYY-MM>.sql data files automatically. Each file is idempotent (CREATE TABLE IF NOT EXISTS, ALTER TABLE ... ADD COLUMN guarded by introspection or a try-catch in pure SQLite, etc.).

Migration runner changes (internal/planning/schema.go):
- On migration: write the migration SQL to <next-N>-schema-<slug>.sql in each affected table directory, then apply it locally via the existing transaction-wrapped runner. Update schema_migrations table.
- On import: schema files are part of the lexicographic replay — they apply via CREATE TABLE IF NOT EXISTS / ALTER TABLE patterns and the schema_migrations table tracks what''s been applied. Replicas pulling new schema files apply them on next import.
- Include canonical_version metadata in the schema files so canonicalisation rule changes (per T-17) are visible alongside structural migrations.

This keeps D-6''s runner architecture (transactional, forward-only, in-house) but moves the migration artefact into the committed changelog so it travels with data and is replayable by any SQLite tool.

Touches: internal/planning/schema.go (migration emission + replay path), schema_migrations table interaction, internal/cli/init.go (T-22 generates the initial 0000-schema.sql via this same path). Tests: migration writes the file and applies it; replica pulls the file and applies via replay; conflicting concurrent migrations on different replicas converge cleanly.', 'backlog', 'medium', NULL, NULL, 'D-15', '2026-05-08 07:48:00', '2026-05-08 07:48:00', NULL, '3acb36c0ab5833bf4f50c71187c4bd09', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-25', 'task', 'T-16', 'multi-machine integration test scenario with clide', 'Use the clide repo (postmeridiem/clide) as the integration test bed for the new replication flow. clide has the right shape: multi-machine, multi-branch, real concurrent edits, decisions sourced from markdown, custom git hooks integrating with pql''s hook chain — which is exactly what produced the original pql-plan.json merge conflict that motivated this work.

Test protocol:
1. Migration test: clone clide at HEAD (which still has pql-plan.json), run upgraded pql, observe the transparent migration from T-23 — pql-plan.json removed, .pql/changelog/ populated, audit log preserved.
2. Concurrent-commit test: two clones, each makes a different ticket transition (one closes a bug, the other opens a feature ticket). Both push. Second push should fast-forward without conflict because per-table monthly files diverge cleanly. Pull on the now-merged main shows both transitions in the consolidated pql.db.
3. Concurrent same-ticket test: two clones edit T-XX.status to different values. Both push. Second push pulls and consolidates; LWW resolves to the later (commit-time, hash) edit. No data loss, no manual conflict resolution.
4. Branch-switch test: switch between branches with diverged ticket state. Confirm the post-checkout hook fires the visible rebuild and pql.db reflects only the current branch''s state.
5. Decision-divergence test: edit a decisions/*.md on one machine, transition a ticket on another, both commit + push. Decisions section reflects the markdown edit (still markdown-sourced per D-8); ticket transition lands in the consolidated state.

clide accepts the rough edges from the original pql-plan.json conflict for one or two more rebase cycles in exchange for being the integration test bed. Do not patch clide with bridge remediations (no manual merge=union on the legacy file, no disabling the auto-export hook) — the friction is the signal that proves the new design is needed.

Touches: no pql code changes — this is the validation pass after T-17 through T-24 land. Outcome: a write-up of observed behaviour vs expected, plus any bug tickets the test scenario surfaces.', 'backlog', 'medium', NULL, NULL, 'D-15', '2026-05-08 07:48:19', '2026-05-08 07:48:19', NULL, '096531f4a5feb1f7066660b14ad51d6b', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-17', 'task', 'T-16', 'add canonical row columns and content hash to all planning tables', 'Forward migration on every planning table to add three columns: created_at (timestamp, set on INSERT), updated_at (timestamp, set on every write — used as the LWW key and the changelog month-bucketing key), and hash (TEXT, set to H(canonical(row except hash))). Plus a canonical_version column or schema-level marker so canonicalisation rule changes are detectable.

Implement canonical row serialisation in internal/planning/ — a fixed column-order projection with strict value formatting (NULL sentinel, integer vs float distinction, timestamp ISO format). Compute hash at write-finalisation in repo helpers (internal/planning/repo/*.go) on every INSERT/UPDATE so the column is always current.

Inline LWW guard for upserts is the SQL idiom: WHERE excluded.updated_at > target.updated_at OR (excluded.updated_at = target.updated_at AND excluded.hash > target.hash). Codify it in a helper used by both writers (D-16) and exporters (T-19).

Touches: internal/planning/schema.go (forward migration), internal/planning/repo/*.go (write paths), new internal/planning/canonical.go (canonicalisation + hash function). Tests: round-trip determinism (two replicas hash identical content to identical bytes), canonical_version bump triggers re-hash, NULL/edge-value coverage.', 'done', 'high', 'claude', NULL, 'D-16', '2026-05-08 07:46:29', '2026-05-08 09:19:42', NULL, 'b23b44071e4a39b3abd3a1f1cd84c181', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-18', 'task', 'T-16', 'implement soft deletes via deleted_at column', 'Forward migration adding deleted_at (timestamp, NULL = live) to every planning table. Route every existing DELETE through UPDATE ... SET deleted_at = ?. Update every read query in internal/planning/repo/*.go to filter WHERE deleted_at IS NULL by default; add an --include-deleted flag where the surface needs visibility into stubs (e.g. audit, recovery).

Stubs persist in pql.db and the changelog so other replicas know the deletion is intentional rather than missing — without this, replay against a fresh replica would re-INSERT the row. The changelog upsert for a deletion is just a regular line where deleted_at is non-null.

Touches: internal/planning/schema.go (migration), internal/planning/repo/*.go (every read query gains the filter; every delete becomes a soft-delete UPDATE), audit log entries for deletion events (recorded as today). Tests: round-trip soft delete / undelete, replay convergence (replica A deletes, replica B has never seen the row → replay creates the stub, then deletion replays into the stub).

Stub purge / retention is deferred to Q-10. This ticket lands the column and the read-path filter; it does not implement purge.', 'done', 'high', 'claude', NULL, 'D-17', '2026-05-08 07:46:41', '2026-05-08 09:54:33', NULL, '6b7c2ac8e06aceb275ac5ad42bdab4ce', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-19', 'task', 'T-16', 'rewrite pql plan export to emit per-table monthly changelog files', 'Replace the current JSON snapshot export (writes pql-plan.json) with the changelog format: emit SQL upsert lines into .pql/changelog/<table>/<YYYY-MM>.sql, one file per (table, month) combination based on the row''s updated_at.

Export pipeline (internal/cli/plan.go + new internal/planning/changelog/):
1. Read last_export_marker from pql.db meta table (local-only, gitignored side of state).
2. SELECT * FROM <table> WHERE updated_at > last_export_marker, ordered by (updated_at, hash). Two-pass: emit rows whose updated_at falls in the previous month into <prev-month>.sql, then current month into <current-month>.sql. Late-arriving rows for older months are rare but possible after clock corrections / backdated imports — handle the bucket placement by row, not by export time.
3. Each emitted line is an INSERT ... ON CONFLICT(<pk>) DO UPDATE SET ... WHERE excluded.updated_at > target.updated_at OR (excluded.updated_at = target.updated_at AND excluded.hash > target.hash). Use the canonical-projection helper from T-17 so the SQL line is byte-stable across replicas.
4. Append (don''t rewrite — files are append-only by month).
5. Advance last_export_marker after successful write.

Stage written files via git add (the existing --stage flag pattern from T-5).

Touches: internal/cli/plan.go (export verb body), new internal/planning/changelog/exporter.go, internal/planning/repo/meta.go (marker storage). Tests: round-trip with T-20 import; same-millisecond rows get sorted deterministically by hash; previous-month bucket only touched when rows belong there.

Decisions still source from markdown, not changelog (D-8 preserved) — exporter skips the decisions table.', 'in_progress', 'high', 'claude', NULL, 'D-15', '2026-05-08 07:46:54', '2026-05-08 10:11:56', NULL, '3195c592de10270a30179b285a315807', 1) ON CONFLICT(id) DO UPDATE SET type=excluded.type, parent_id=excluded.parent_id, title=excluded.title, description=excluded.description, status=excluded.status, priority=excluded.priority, assigned_to=excluded.assigned_to, team=excluded.team, decision_ref=excluded.decision_ref, updated_at=excluded.updated_at, deleted_at=excluded.deleted_at, hash=excluded.hash, canonical_version=excluded.canonical_version WHERE excluded.updated_at > tickets.updated_at OR (excluded.updated_at = tickets.updated_at AND excluded.hash > tickets.hash);
INSERT INTO tickets (id, type, parent_id, title, description, status, priority, assigned_to, team, decision_ref, created_at, updated_at, deleted_at, hash, canonical_version) VALUES ('T-19', 'task', 'T-16', 'rewrite pql plan export to emit per-table monthly changelog files', 'Replace the current JSON snapshot export (writes pql-plan.json) with the changelog format: emit SQL upsert lines into .pql/changelog/<table>/<YYYY-MM>.sql, one file per (table, month) combination based on the row''s updated_at.

Export pipeline (internal/cli/plan.go + new internal/planning/changelog/):
1. Read last_export_marker from pql.db meta table (local-only, gitignored side of state).
2. SELECT * FROM <table> WHERE updated_at > last_export_marker, ordered by (updated_at, hash). Two-pass: emit rows whose updated_at falls in the previous month into <prev-month>.sql, then current month into <current-month>.sql. Late-arriving rows for older months are rare but possible after clock corrections / backdated imports — handle the bucket placement by row, not by export time.
3. Each emitted line is an INSERT ... ON CONFLICT(<pk>) DO UPDATE SET ... WHERE excluded.updated_at > target.updated_at OR (excluded.updated_at = target.updated_at AND excluded.hash > target.hash). Use the canonical-projection helper from T-17 so the SQL line is byte-stable across replicas.
4. Append (don''t rewrite — files are append-only by month).
5. Advance last_export_marker after successful write.

Stage written files via git add (the existing --stage flag pattern from T-5).

